CREATE TABLE IF NOT EXISTS "account_disabled_models" ("id" INTEGER GENERATED BY DEFAULT AS IDENTITY NOT NULL PRIMARY KEY, "account_id" INTEGER NOT NULL, "model_name" TEXT NOT NULL, "created_at" TEXT DEFAULT to_char(timezone('UTC', CURRENT_TIMESTAMP), 'YYYY-MM-DD HH24:MI:SS'), FOREIGN KEY ("account_id") REFERENCES "accounts"("id") ON DELETE CASCADE);
CREATE UNIQUE INDEX "account_disabled_models_account_model_unique" ON "account_disabled_models" ("account_id", "model_name");
CREATE INDEX "account_disabled_models_account_id_idx" ON "account_disabled_models" ("account_id");
